class Solution {
public:
    string reverseWords(string s) {
        string word, res;
        int i = 0, n = s.size();
        while (i < n) {
            while (i < n && s[i] == ' ') i++;
            if (i >= n) break;
            int j = i;
            while (j < n && s[j] != ' ') j++;
            word = s.substr(i, j - i);
            res = res.empty() ? word : word + " " + res;
            i = j;
        }
        return res;
    }
};

